// templates/hero/index.ts
import { z } from 'zod'
import type { TemplateFunction } from 'gazetta'

export const schema = z.object({
  title: z.string(),
  subtitle: z.string().optional(),
})

type Content = z.infer<typeof schema>

const template: TemplateFunction<Content> = ({ content }) => ({
  html: `<h1>${content?.title ?? ''}</h1>
         <p>${content?.subtitle ?? ''}</p>`,
  css: `h1 { font-size: 3rem; }`,
  js: '',
})

export default template

// templates/card/index.tsx
import React from 'react'
import { renderToStaticMarkup } from 'react-dom/server'
import { z } from 'zod'
import type { TemplateFunction } from 'gazetta'

export const schema = z.object({
  icon: z.string(),
  title: z.string(),
  description: z.string(),
})

type Content = z.infer<typeof schema>

function Card({ icon, title, description }: Content) {
  return (
    <div className="card">
      <span>{icon}</span>
      <h3>{title}</h3>
      <p>{description}</p>
    </div>
  )
}

const template: TemplateFunction<Content> = ({ content }) => ({
  html: renderToStaticMarkup(
    <Card {...content!} />
  ),
  css: `.card { padding: 1.5rem; border-radius: 8px; }`,
  js: '',
})

export default template

// templates/quote/index.ts
import { createSSRApp, h } from 'vue'
import { renderToString } from 'vue/server-renderer'
import { z } from 'zod'
import type { TemplateFunction } from 'gazetta'

export const schema = z.object({
  quote: z.string(),
  author: z.string(),
})

type Content = z.infer<typeof schema>

const Quote = (props: Content) => h('blockquote', [
  h('p', `"${props.quote}"`),
  h('footer', props.author),
])

const template: TemplateFunction<Content> = async ({ content }) => {
  const app = createSSRApp(Quote, content ?? {})
  const html = await renderToString(app)
  return {
    html,
    css: `blockquote { border-left: 3px solid #667eea; padding: 1rem 2rem; }`,
    js: '',
  }
}

export default template
